// HasScan applies the HasEdge predicate on the "scan" edge.
func HasScan() predicate.ImportScanFile {
	return predicate.ImportScanFile(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ScanTable, ScanColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasScanWith applies the HasEdge predicate on the "scan" edge with a given conditions (other predicates).
func HasScanWith(preds ...predicate.ImportScan) predicate.ImportScanFile {
	return predicate.ImportScanFile(func(s *sql.Selector) {
		step := newScanStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ImportScanFile) predicate.ImportScanFile {
	return predicate.ImportScanFile(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ImportScanFile) predicate.ImportScanFile {
	return predicate.ImportScanFile(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ImportScanFile) predicate.ImportScanFile {
	return predicate.ImportScanFile(sql.NotPredicates(p))
}
